var logs = ($json.logs || []).slice();
var tentativa = $json.tentativa || $json.retry_count || 0;
var textoLimpo = $json.texto_limpo || '';
var ts = new Date().toISOString();

logs.push('[' + ts + '][ERRO FINAL] Todas as ' + tentativa + ' tentativas de extracao via IA falharam');
logs.push('[' + ts + '][ERRO FINAL] Campos obrigatorios (nome e/ou telefone) nao puderam ser extraidos');
logs.push('[' + ts + '][ERRO FINAL] Arquivo encaminhado para fila de revisao manual');

var motivo = 'Extracao falhou apos ' + tentativa + ' tentativas: campos obrigatorios ausentes (nome e/ou telefone)';

return [{ json: {
  status: 'revisao_manual',
  motivo_erro: motivo,
  tentativas_realizadas: tentativa,
  texto_trecho: textoLimpo.substring(0, 1000),
  log_completo: logs.join('\n'),
  timestamp: ts
} }];

var sq = String.fromCharCode(39);
var escape = function(v) { return String(v).split(sq).join(sq + sq); };

var texto = escape(($json.texto_trecho || '').substring(0, 1000));
var motivo = escape($json.motivo_erro || 'Erro desconhecido');
var logTxt = escape(($json.log_completo || '').substring(0, 5000));
var tentativas = parseInt($json.tentativas_realizadas || 0);

var sql = 'INSERT INTO revisao_manual (texto_trecho, motivo_erro, log_completo, tentativas_realizadas, criado_em) VALUES (' + sq + texto + sq + ', ' + sq + motivo + sq + ', ' + sq + logTxt + sq + ', ' + tentativas + ', NOW());';

return [{ json: {
  sql_revisao: sql,
  motivo_erro: $json.motivo_erro,
  log_completo: $json.log_completo,
  tentativas: tentativas
} }];

return [{ json: {
  status: 'erro',
  mensagem: $json.motivo_erro || 'Falha no processamento',
  tentativas_realizadas: $json.tentativas,
  log_completo: $json.log_completo,
  timestamp: new Date().toISOString()
} }];

// Recupera as palavras buscadas do nó anterior
const palavras = $('Montar SQL1').first().json.palavras;

// Faz o parse do resultado do banco
let candidatos = $json.candidatos;
if (typeof candidatos === 'string') {
  try { candidatos = JSON.parse(candidatos); } catch(e) { candidatos = []; }
}
if (!Array.isArray(candidatos)) { candidatos = []; }

// Retorno direto: encontrou ou não
if (candidatos.length === 0) {
  return [{ json: {
    total: 0,
    palavras_buscadas: palavras,
    candidatos: [],
    mensagem: 'Nenhum candidato encontrado para as palavras-chave informadas.'
  }}];
}

return [{ json: {
  total: candidatos.length,
  palavras_buscadas: palavras,
  candidatos
}}];

// Payload esperado:
// { "palavras": ["Desenvolvimento", "Software"], "limite": 10 }

const body = $json.body || $json;

// Aceita tanto array (novo) quanto string separada por vírgula (compatibilidade)
let palavras = body.palavras || [];
if (typeof palavras === 'string') {
  palavras = palavras.split(',').map(p => p.trim()).filter(Boolean);
}

const limite = Math.min(parseInt(body.limite) || 10, 50);

const esc = s => (s || '').replace(/'/g, "''");

// Busca full-text: cada palavra é procurada em TODOS os campos relevantes
const conditions = palavras.map(p => {
  const v = esc(p);
  return `(
    nome_completo    ILIKE '%${v}%' OR
    cargo_pretendido ILIKE '%${v}%' OR
    habilidades      ILIKE '%${v}%' OR
    localizacao      ILIKE '%${v}%' OR
    texto_curriculo  ILIKE '%${v}%'
  )`;
});

// AND entre palavras (todas devem aparecer), OR entre campos
const where = conditions.length ? `WHERE ${conditions.join(' AND ')}` : '';

const sql = `
  SELECT COALESCE(json_agg(row_to_json(c)), '[]'::json) AS candidatos
  FROM (
    SELECT
      telefone,
      nome_completo,
      cargo_pretendido,
      habilidades,
      localizacao,
      nome_arquivo,
      LEFT(texto_curriculo, 300) AS experiencia_resumida,
      criado_em
    FROM candidatos
    ${where}
    LIMIT ${limite}
  ) c
`;

return [{ json: { sql, palavras, limite } }];

// Verifica se a resposta da IA é válida
const content =
  $json.content ||
  ($json.message && $json.message.content) ||
  ($json.choices && $json.choices[0] && $json.choices[0].message && $json.choices[0].message.content) ||
  null;

// Recupera contexto do nó Preparar Chat
const ctx = $('Preparar Chat1').first().json;

if (!content) {
  // Sem conteúdo válido — trata como erro
  return [{
    json: {
      erro: true,
      mensagem: ctx.mensagem,
      candidatosStr: ctx.candidatosStr,
      historicoFormatado: ctx.historicoFormatado,
      tentativa: ctx.tentativa,
      maxTentativas: ctx.maxTentativas
    }
  }];
}

// Sucesso — monta resposta final
const historicoAtualizado = [
  ...ctx.historicoFormatado,
  { role: 'user', content: ctx.mensagem },
  { role: 'assistant', content: content }
];

return [{ json: {
  erro: false,
  resposta: content,
  historico: historicoAtualizado
}}];

// Verifica se ainda há tentativas disponíveis
const tentativa = $json.tentativa || 1;
const maxTentativas = $json.maxTentativas || 3;

if (tentativa >= maxTentativas) {
  // Esgotou todas as tentativas
  return [{ json: {
    podetentar: false,
    tentativa,
    maxTentativas,
    mensagem: $json.mensagem,
    candidatosStr: $json.candidatosStr,
    historicoFormatado: $json.historicoFormatado
  }}];
}

// Ainda pode tentar: aguarda 5 segundos
await new Promise(resolve => setTimeout(resolve, 5000));

// Incrementa tentativa e repassa o contexto
return [{ json: {
  podetentar: true,
  tentativa: tentativa + 1,
  maxTentativas,
  mensagem: $json.mensagem,
  candidatosStr: $json.candidatosStr,
  historicoFormatado: $json.historicoFormatado
}}];

// Todas as tentativas falharam — retorna erro amigável
return [{ json: {
  resposta: null,
  erro: true,
  mensagem: 'Não foi possível obter resposta da IA após 3 tentativas. Tente novamente em instantes.',
  historico: $json.historicoFormatado || []
}}];

// Resposta de sucesso — limpa campos internos e retorna apenas o necessário
return [{ json: {
  resposta: $json.resposta,
  historico: $json.historico
}}];

const body = $json.body || $json;

const mensagem = (body.mensagem || '').trim();
const candidatos = Array.isArray(body.candidatos) ? body.candidatos : [];
const historico = Array.isArray(body.historico) ? body.historico : [];

if (!mensagem) {
  throw new Error('Campo "mensagem" é obrigatório.');
}

const candidatosStr = candidatos.length
  ? candidatos.map((c, i) =>
      `[Candidato ${i + 1}]\n` +
      `  Nome: ${c.nome_completo || 'N/A'}\n` +
      `  Telefone: ${c.telefone || 'N/A'}\n` +
      `  Cargo pretendido: ${c.cargo_pretendido || 'N/A'}\n` +
      `  Habilidades: ${c.habilidades || 'N/A'}\n` +
      `  Localização: ${c.localizacao || 'N/A'}\n` +
      `  Resumo: ${(c.experiencia_resumida || '').substring(0, 300)}`
    ).join('\n\n')
  : 'Nenhum candidato fornecido.';

const historicoFormatado = historico
  .filter(h => h.role && h.content)
  .map(h => ({ role: h.role, content: String(h.content) }));

// Inicializa contador de tentativas
return [{ json: {
  mensagem,
  candidatosStr,
  historicoFormatado,
  totalCandidatos: candidatos.length,
  tentativa: 1,
  maxTentativas: 3
}}];

const items = $input.all();

if (items.length === 0 || !items[0].json || !items[0].json.telefone) {
  return [{ json: { existe: false, telefone: $('Extrair Telefone1').item.json.telefone } }];
}

const telefoneFormatado = items[0].json.telefone;

return [{ json: { existe: true, telefone: telefoneFormatado } }];

const texto = $('Limpar Texto').item.json.texto_limpo || '';

const regex = /(\(?\d{2}\)?)\s?[9]?\d{4}[-\s]?\d{4}/g;
const matches = texto.match(regex);

if (!matches || matches.length === 0) {
  throw new Error('Nenhum telefone encontrado no currículo.');
}

const telefone = matches[0].replace(/\D/g, '');

return [{ json: { telefone, texto_limpo: texto } }];

const content =
  $json.content ||
  $json.message?.content ||
  $json.choices?.[0]?.message?.content ||
  $json.text ||
  '';

if (!content) {
  throw new Error(
    'Não foi possível extrair o SQL da resposta da IA.\nJSON recebido: ' +
    JSON.stringify($json, null, 2)
  );
}

let sql = content.trim();
sql = sql.replace(/```sql\s*/gi, '').replace(/```\s*/g, '').trim();

const upperSql = sql.toUpperCase();
if (!upperSql.startsWith('INSERT') && !upperSql.startsWith('UPDATE')) {
  throw new Error('A IA não retornou um INSERT ou UPDATE válido.\nResposta: ' + sql);
}

return [{ json: { sql_insert: sql } }];

const body = $input.first().json.body || $input.first().json;

// Valida campos obrigatórios
if (!body.participant?.telefone) {
  throw new Error('Campo obrigatório ausente: participant.telefone');
}
if (!body.scores) {
  throw new Error('Campo obrigatório ausente: scores');
}

const telefone = body.participant.telefone.replace(/\D/g, '');
const exportDate = body.exportDate || null;

// Monta objeto resultado sem os dados de answers (muito volumoso) — inclua se quiser
const resultado = JSON.stringify(body);

return [{
  json: {
    telefone,
    tipo_avaliacao: 'hogan',
    export_date: exportDate,
    resultado
  }
}];

const items = $input.all();
const encontrou = items.length > 0 && !!items[0].json?.telefone;

if (!encontrou) {
  return [{
    json: {
      valido: "false",
      telefone: $('Preparar Dados').item.json.telefone,
      tipo_avaliacao: $('Preparar Dados').item.json.tipo_avaliacao,
      export_date: $('Preparar Dados').item.json.export_date,
      resultado: $('Preparar Dados').item.json.resultado
    }
  }];
}

return [{
  json: {
    valido: "true",
    telefone: items[0].json.telefone,
    tipo_avaliacao: $('Preparar Dados').item.json.tipo_avaliacao,
    export_date: $('Preparar Dados').item.json.export_date,
    resultado: $('Preparar Dados').item.json.resultado
  }
}];

const body = $json.body || $json;

// Aceita qualquer formato: (11) 90810-2064 | 11 90810-2064 | 11908102064
const rawPhone = String(body.telefone || '').trim();

if (!rawPhone) {
  throw new Error('Campo obrigatório ausente: telefone');
}

// Remove tudo que não for dígito para comparação
const digits = rawPhone.replace(/\D/g, '');

if (digits.length < 8) {
  throw new Error('Telefone inválido: ' + rawPhone);
}

// A query normaliza AMBOS os lados: tanto o buscado quanto o armazenado
// Isso garante match independente do formato salvo no banco
const sql = `
  SELECT
    id,
    telefone_candidato,
    tipo_avaliacao,
    export_date,
    resultado,
    criado_em
  FROM candidato_avaliacoes
  WHERE REGEXP_REPLACE(telefone_candidato, '[^0-9]', '', 'g') = '${digits}'
  ORDER BY criado_em DESC
  LIMIT 10
`;

return [{ json: { sql, telefone_original: rawPhone, digits } }];

const sqlNode = $('Normalizar Telefone e Montar SQL').first().json;
const rows    = $input.all().map(i => i.json).filter(r => r && r.id);

// Parse do campo resultado (JSON string → objeto)
const avaliacoes = rows.map(r => {
  let resultado = r.resultado;
  if (typeof resultado === 'string') {
    try { resultado = JSON.parse(resultado); } catch(e) { resultado = null; }
  }
  return {
    id:                  r.id,
    telefone_candidato:  r.telefone_candidato,
    tipo_avaliacao:      r.tipo_avaliacao,
    export_date:         r.export_date,
    criado_em:           r.criado_em,
    // Dados do participante extraídos do resultado
    participante:        resultado && resultado.participant ? resultado.participant : null,
    // Scores resumidos para exibição rápida
    scores:              resultado && resultado.scores     ? resultado.scores     : null,
    // Resultado completo (opcional — remova se quiser resposta menor)
    resultado
  };
});

return [{
  json: {
    telefone_buscado: sqlNode.telefone_original,
    total:            avaliacoes.length,
    avaliacoes
  }
}];
